// ============================================================================
// Dialog Widget
// ============================================================================

struct Dialog : Widget {
    bool modal = true;
    bool visible = false;

    const wchar_t* title = L"";
    IDWriteTextFormat* title_format = nullptr;  // nullptr = use default

    // Appearance
    float dialog_width = BranchDialog::WIDTH;   // 400.0f
    float dialog_height = 0.0f;                 // Set by show() or auto-height
    float corner_radius = BranchDialog::CORNER_RADIUS;  // 8.0f
    float title_height = BranchDialog::TITLE_HEIGHT;    // 48.0f

    // Auto-height mode: compute dialog_height from content
    bool auto_height = false;
    float min_height = 100.0f;  // Minimum dialog height when auto_height
    float max_height = 0.0f;    // Maximum dialog height (0 = screen height - margin)

    uint32_t overlay_color = BranchDialog::OVERLAY_BG;  // 0xB3000000
    uint32_t bg_color = BranchDialog::DIALOG_BG;        // 0xFF2D2D30
    uint32_t title_color = Theme::TEXT_PRIMARY;

    // Close button
    float close_button_size = BranchDialog::CLOSE_BUTTON_SIZE;  // 32.0f
    bool close_button_hovered = false;

    // Content container (child widget to hold dialog content)
    Widget* content = nullptr;

    // Callbacks
    void (*on_close)(Dialog* dlg, void* user_data) = nullptr;
    void* user_data = nullptr;

    Dialog() {
        // Dialog fills the entire window
        width_mode = SizeMode::Fill;
        height_mode = SizeMode::Fill;
        flags |= WidgetFlags::RendersOwnChildren;  // We render content explicitly with positioning
    }

    void measure(const LayoutConstraints& constraints) override {
        // Dialog fills available space (the overlay covers the whole window)
        rect.width = constraints.max_width;
        rect.height = constraints.max_height;

        // Measure content if present
        if (content && visible) {
            LayoutConstraints content_constraints;
            content_constraints.max_width = dialog_width - DialogBase::PADDING * 2;

            if (auto_height) {
                // For auto-height, measure content with unlimited height to get true preferred size
                content_constraints.max_height = 100000.0f;
                content->measure(content_constraints);

                // Compute dialog height from content's preferred height
                float computed = title_height + content->preferred_height + DialogBase::PADDING;
                float max_h = max_height > 0 ? max_height : (constraints.max_height - 100.0f);
                dialog_height = fminf(fmaxf(computed, min_height), max_h);
            } else {
                // Fixed height mode - measure content within allocated space
                content_constraints.max_height = dialog_height - title_height - DialogBase::PADDING;
                content->measure(content_constraints);
            }
        }
    }

    void layout() override {
        if (!visible) return;

        // Center the dialog
        float dialog_x = (rect.width - dialog_width) / 2.0f;
        float dialog_y = (rect.height - dialog_height) / 2.0f;

        // Layout content
        if (content) {
            content->rect.x = dialog_x + DialogBase::PADDING;
            content->rect.y = dialog_y + title_height;
            content->rect.width = dialog_width - DialogBase::PADDING * 2;
            content->rect.height = dialog_height - title_height - DialogBase::PADDING; // Bottom padding only
            content->layout();
        }
    }

    void render(RenderContext& ctx) override {
        if (!visible) return;

        // Draw overlay
        if (modal) {
            D2D1_RECT_F overlay_rect = D2D1::RectF(0, 0, rect.width, rect.height);
            ctx.fill_rect(overlay_rect, overlay_color);
        }

        // Calculate dialog position (centered)
        float dialog_x = (rect.width - dialog_width) / 2.0f;
        float dialog_y = (rect.height - dialog_height) / 2.0f;

        D2D1_RECT_F dialog_rect = D2D1::RectF(
            dialog_x, dialog_y,
            dialog_x + dialog_width, dialog_y + dialog_height
        );

        // Draw dialog shadow
        ctx.draw_dialog_shadow(dialog_rect, corner_radius);

        // Draw dialog background
        ctx.fill_rounded_rect(dialog_rect, corner_radius, bg_color);

        // Draw title bar
        if (title && title[0]) {
            IDWriteTextFormat* fmt = title_format ? title_format : g_text_format_body;
            if (fmt) {
                D2D1_RECT_F title_rect = D2D1::RectF(
                    dialog_x + DialogBase::PADDING,
                    dialog_y,
                    dialog_x + dialog_width - close_button_size - 8.0f,
                    dialog_y + title_height
                );
                ctx.draw_text(title, wcslen(title), fmt, title_rect, title_color);
            }
        }

        // Draw close button
        float close_x = dialog_x + dialog_width - close_button_size - 8.0f;
        float close_y = dialog_y + (title_height - close_button_size) / 2.0f;

        if (close_button_hovered) {
            D2D1_RECT_F close_bg = D2D1::RectF(
                close_x, close_y,
                close_x + close_button_size, close_y + close_button_size
            );
            ctx.fill_rounded_rect(close_bg, 4.0f, Theme::BG_HOVER);
        }

        // Draw X icon
        float cx = close_x + close_button_size / 2.0f;
        float cy = close_y + close_button_size / 2.0f;
        float x_size = 5.0f;
        ctx.draw_line(cx - x_size, cy - x_size, cx + x_size, cy + x_size, Theme::TEXT_PRIMARY, 1.5f);
        ctx.draw_line(cx + x_size, cy - x_size, cx - x_size, cy + x_size, Theme::TEXT_PRIMARY, 1.5f);

        // Render content
        if (content) {
            content->render(ctx);
        }
    }

    bool on_mouse_move(float x, float y) override {
        if (!visible) return false;

        // Check close button hover
        float dialog_x = (rect.width - dialog_width) / 2.0f;
        float dialog_y = (rect.height - dialog_height) / 2.0f;
        float close_x = dialog_x + dialog_width - close_button_size - 8.0f;
        float close_y = dialog_y + (title_height - close_button_size) / 2.0f;

        bool was_hovered = close_button_hovered;
        close_button_hovered = (x >= close_x && x < close_x + close_button_size &&
                                y >= close_y && y < close_y + close_button_size);

        if (was_hovered != close_button_hovered) {
            set_dirty();
        }

        return true;  // Dialog captures all mouse moves when visible
    }

    bool on_mouse_down(float x, float y, int button) override {
        (void)button;
        if (!visible) return false;

        float dialog_x = (rect.width - dialog_width) / 2.0f;
        float dialog_y = (rect.height - dialog_height) / 2.0f;

        // Check close button click
        float close_x = dialog_x + dialog_width - close_button_size - 8.0f;
        float close_y = dialog_y + (title_height - close_button_size) / 2.0f;

        if (x >= close_x && x < close_x + close_button_size &&
            y >= close_y && y < close_y + close_button_size) {
            close();
            return true;
        }

        // Check if click is outside dialog (dismiss modal)
        if (modal) {
            if (x < dialog_x || x >= dialog_x + dialog_width ||
                y < dialog_y || y >= dialog_y + dialog_height) {
                close();
                return true;
            }
        }

        return true;  // Dialog captures all clicks when visible
    }

    bool on_key_down(int vk, bool ctrl, bool shift, bool alt) override {
        (void)ctrl; (void)shift; (void)alt;
        if (!visible) return false;

        // Escape closes the dialog
        if (vk == VK_ESCAPE) {
            close();
            return true;
        }

        return true;  // Dialog captures all keys when visible (prevents input below)
    }

    void show() {
        visible = true;
        flags |= WidgetFlags::Visible;
        set_dirty();
    }

    void close() {
        visible = false;
        flags &= ~WidgetFlags::Visible;
        close_button_hovered = false;

        if (on_close) {
            on_close(this, user_data);
        }

        set_dirty();
    }

    // Helper to set content and add it as child
    void set_content(Widget* new_content) {
        // Remove old content if any
        if (content) {
            widget_remove_child(this, content);
        }

        content = new_content;

        if (content) {
            widget_add_child(this, content);
        }
    }
};

// ============================================================================
// DialogWidget - Base class for modal dialog widgets
// ============================================================================
//
// Encapsulates common patterns across all dialog widgets:
// - Global instance management
// - Dialog creation and lifecycle
// - Event dispatcher setup
// - Measure/layout boilerplate
// - Render and is_active utilities
//
// Derived classes implement virtual methods for customization:
// - populate_content(): Create dialog-specific UI elements
// - set_initial_focus(): Set focus to appropriate widget after show
// - on_close(): Handle cleanup when dialog closes (optional)
//
// Usage pattern:
//   struct MyDialogWidget : DialogWidget {
//       void populate_content() override;
//       void set_initial_focus() override;
//   };
//
//   void show_my_dialog() {
//       MyDialogWidget::instance = g_widget_arena.create<MyDialogWidget>();
//       MyDialogWidget::instance->show(L"Dialog Title", 400, 300);
//   }
// ============================================================================

// Forward declarations for functions defined in platform_dialogs.cpp
bool any_dialog_widget_is_active();

// Forward declaration for callback used in show()
static void dialog_widget_on_close(Dialog* dlg, void* user_data);

// Prepare arena for new dialog allocation - call BEFORE creating DialogWidget
// NOTE: We no longer reset the arena because persistent widgets (titlebar, sidebar,
// welcome screen elements) are allocated from the same arena and must not be invalidated.
// Dialog memory accumulates but is bounded by dialog usage per session.
// A future improvement could use a separate arena for dialogs.
void dialog_arena_prepare() {
    // No-op for now - arena reset removed to preserve persistent widgets
}

struct DialogWidget {
    // Common members
    Dialog* dialog = nullptr;
    FlexContainer* content = nullptr;
    WidgetTree tree = {};

    // Static instance access (each derived class sets its own static member)
    static DialogWidget* instance;

    // Virtual methods for customization
    virtual void populate_content() = 0;
    virtual void set_initial_focus() {}
    virtual void on_close() {}

    // Common methods
    virtual void close() {
        if (dialog) {
            dialog->close();
        }
        LOG("[DIALOG] close() - setting g_event_dispatcher.root = nullptr (was id=%u name='%s')",
            g_event_dispatcher.root ? g_event_dispatcher.root->id : 0,
            g_event_dispatcher.root && g_event_dispatcher.root->debug_name ? g_event_dispatcher.root->debug_name : "(null)");
        g_event_dispatcher.root = nullptr;
        g_event_dispatcher.focused = nullptr;
        // Clear captured/hovered too — these may point into the dialog tree which
        // is about to be unreachable; leaving them dangling can cause UAF on the
        // next mouse_up/mouse_move.
        g_event_dispatcher.captured = nullptr;
        g_event_dispatcher.hovered = nullptr;
#ifndef GITSMARTER_TEST_BUILD
        InvalidateRect(g_main_window, nullptr, FALSE);
#endif
    }

    bool is_active() const {
        return dialog && dialog->visible;
    }

    void show(const wchar_t* title, float width, float height) {
        // NOTE: Arena reset is now handled by dialog_arena_prepare() which must be
        // called BEFORE allocating the DialogWidget subclass (in *_dialog_widget_show)

        // Create dialog
        dialog = g_widget_arena.create<Dialog>();
        dialog->title = title;
        dialog->dialog_width = width;
        dialog->dialog_height = height;
        dialog->on_close = dialog_widget_on_close;
        dialog->user_data = this;
        dialog->debug_name = "dialog_root";  // DEBUG

        // Create content container
        content = g_widget_arena.create<FlexContainer>();
        content->direction = FlexDirection::Column;
        content->align = FlexAlign::Stretch;
        content->gap = 4.0f;
        content->debug_name = "dialog_content";  // DEBUG

        // Virtual hook: populate dialog-specific widgets
        populate_content();

        // Set content and show
        dialog->set_content(content);
        dialog->show();

        // Event dispatcher setup
        LOG("[DIALOG] show() - setting g_event_dispatcher.root = dialog (id=%u name='%s')",
            dialog->id, dialog->debug_name ? dialog->debug_name : "(null)");
        g_event_dispatcher.root = dialog;
        tree.root = dialog;

        // Measure and layout
        measure_and_layout();

        // Virtual hook: set initial focus
        set_initial_focus();

#ifndef GITSMARTER_TEST_BUILD
        InvalidateRect(g_main_window, nullptr, FALSE);
#endif
    }

    // Auto-height overload: dialog height computed from content
    void show(const wchar_t* title, float width) {
        // NOTE: Arena reset is now handled by dialog_arena_prepare() which must be
        // called BEFORE allocating the DialogWidget subclass (in *_dialog_widget_show)

        // Create dialog with auto-height enabled
        dialog = g_widget_arena.create<Dialog>();
        dialog->title = title;
        dialog->dialog_width = width;
        dialog->auto_height = true;
        dialog->on_close = dialog_widget_on_close;
        dialog->user_data = this;
        dialog->debug_name = "dialog_root";

        // Create content container
        content = g_widget_arena.create<FlexContainer>();
        content->direction = FlexDirection::Column;
        content->align = FlexAlign::Stretch;
        content->gap = 4.0f;
        content->debug_name = "dialog_content";

        // Virtual hook: populate dialog-specific widgets
        populate_content();

        // Set content and show
        dialog->set_content(content);
        dialog->show();

        // Event dispatcher setup
        LOG("[DIALOG] show() auto-height - setting g_event_dispatcher.root = dialog (id=%u)",
            dialog->id);
        g_event_dispatcher.root = dialog;
        tree.root = dialog;

        // Measure and layout
        measure_and_layout();

        // Virtual hook: set initial focus
        set_initial_focus();

#ifndef GITSMARTER_TEST_BUILD
        InvalidateRect(g_main_window, nullptr, FALSE);
#endif
    }

    void measure_and_layout() {
        LayoutConstraints constraints;
        if (g_render_target) {
            D2D1_SIZE_F size = g_render_target->GetSize();
            constraints.max_width = size.width;
            constraints.max_height = size.height;
        } else {
            constraints.max_width = 1280.0f;
            constraints.max_height = 720.0f;
        }

        LayoutEngine::measure_tree(dialog, constraints);
        dialog->rect.x = 0;
        dialog->rect.y = 0;
        dialog->rect.width = constraints.max_width;
        dialog->rect.height = constraints.max_height;
        LayoutEngine::layout_tree(dialog);

#ifdef GITSMARTER_DEBUG_LAYOUT_DUMP
        debug_dump_tree(dialog, 0);
#endif
    }

#ifdef GITSMARTER_DEBUG_LAYOUT_DUMP
    // Recursively dump widget tree with computed rects (opt-in debug only)
    void debug_dump_tree(Widget* w, int depth) {
        if (!w) return;
        char indent[64] = {};
        for (int i = 0; i < depth && i < 30; i++) {
            indent[i*2] = ' ';
            indent[i*2+1] = ' ';
        }
        indent[depth*2] = '\0';
        LOG("[LAYOUT] %sid=%u name='%s' rect=(%.0f,%.0f,%.0f,%.0f) pref=(%.0f,%.0f)",
            indent, w->id,
            w->debug_name ? w->debug_name : "(null)",
            w->rect.x, w->rect.y, w->rect.width, w->rect.height,
            w->preferred_width, w->preferred_height);
        for (Widget* c = w->first_child; c; c = c->next_sibling) {
            debug_dump_tree(c, depth + 1);
        }
    }
#endif

    void render() {
        if (!dialog || !dialog->visible || !g_render_target) {
            return;
        }
        tree.render(g_render_target);
    }
};

// Static instance (base class, overridden by derived classes)
DialogWidget* DialogWidget::instance = nullptr;

// Common close callback for all dialog widgets
static void dialog_widget_on_close(Dialog* dlg, void* user_data) {
    (void)dlg;
    DialogWidget* widget = static_cast<DialogWidget*>(user_data);
    if (widget) {
        widget->on_close();
        g_event_dispatcher.root = nullptr;
        g_event_dispatcher.focused = nullptr;
        // Clear captured/hovered to avoid dangling pointers into the closed dialog.
        g_event_dispatcher.captured = nullptr;
        g_event_dispatcher.hovered = nullptr;
    }
#ifndef GITSMARTER_TEST_BUILD
    InvalidateRect(g_main_window, nullptr, FALSE);
#endif
}

// ============================================================================
// ScrollContainer Widget
// ============================================================================

// Helper: propagate viewport bounds to virtualized widget descendants
// Uses virtual on_viewport_changed() instead of RTTI dynamic_cast for performance
static void propagate_viewport_to_virtualized_widgets(Widget* widget, float vp_top, float vp_bottom) {
    if (!widget) return;

    // Call virtual method - widgets that care about viewport override this
    widget->on_viewport_changed(vp_top, vp_bottom);

    // Recurse into children
    for (Widget* child = widget->first_child; child; child = child->next_sibling) {
        propagate_viewport_to_virtualized_widgets(child, vp_top, vp_bottom);
    }
}

struct ScrollContainer : Widget {
    // Scroll position
    float scroll_x = 0.0f;
    float scroll_y = 0.0f;

    // Virtual content size (computed from children)
    float content_width = 0.0f;
    float content_height = 0.0f;

    // Scrollbar visibility
    bool show_scrollbar_h = false;
    bool show_scrollbar_v = true;

    // Scrollbar appearance (using existing constants)
    float scrollbar_width = Sidebar::SCROLLBAR_WIDTH;          // 14.0f
    float scrollbar_min_thumb = Sidebar::SCROLLBAR_MIN_THUMB;  // 30.0f
    float scrollbar_button_size = Sidebar::SCROLLBAR_BUTTON_SIZE;  // 14.0f
    float scrollbar_thumb_margin = Sidebar::SCROLLBAR_THUMB_MARGIN;  // 2.0f
    float scroll_speed = DiffViewer::SCROLL_SPEED;             // 40.0f

    // Scrollbar colors
    uint32_t scrollbar_track_color = Theme::BG_SECONDARY;      // 0xFF252526
    uint32_t scrollbar_thumb_color = Theme::BG_HOVER;          // 0xFF3E3E42
    uint32_t scrollbar_button_color = Theme::TEXT_MUTED;       // 0xFF6D6D6D

    // Scrollbar interaction state
    bool scrollbar_dragging = false;
    float drag_start_y = 0.0f;
    float drag_start_offset = 0.0f;

    // Hover state for scrollbar parts
    enum class ScrollbarHover { None, UpButton, DownButton, Thumb, Track };
    ScrollbarHover scrollbar_hover = ScrollbarHover::None;

    // Cached scrollbar geometry (vertical)
    float thumb_top = 0.0f;
    float thumb_bottom = 0.0f;
    float track_top = 0.0f;
    float track_bottom = 0.0f;

    // Horizontal scrollbar interaction state
    bool scrollbar_dragging_h = false;
    float drag_start_x = 0.0f;
    float drag_start_offset_x = 0.0f;

    // Horizontal hover state
    enum class ScrollbarHoverH { None, LeftButton, RightButton, Thumb, Track };
    ScrollbarHoverH scrollbar_hover_h = ScrollbarHoverH::None;

    // Cached horizontal scrollbar geometry
    float thumb_left_h = 0.0f;
    float thumb_right_h = 0.0f;
    float track_left_h = 0.0f;
    float track_right_h = 0.0f;

    // Scroll momentum for smooth scrolling
    ScrollMomentum scroll_momentum_v;
    ScrollMomentum scroll_momentum_h;
    float accumulated_time = 0.0f;  // Time tracker for scroll input detection

    // Track which child received mouse_down for proper mouse_up forwarding
    Widget* mouse_down_child = nullptr;

    ScrollContainer() {
        flags |= WidgetFlags::ClipChildren;
        flags |= WidgetFlags::CapturesMouse;  // Capture mouse during scrollbar drag
        flags |= WidgetFlags::RendersOwnChildren;  // We handle child rendering with viewport culling
    }

    void tick(float dt) override {
        Widget::tick(dt);
        accumulated_time += dt;

        // Update scroll momentum (only animates after finger release)
        float viewport_height = rect.height - (show_scrollbar_h ? scrollbar_width : 0.0f);
        float max_scroll_y = fmaxf(0.0f, content_height - viewport_height);

        float viewport_width = rect.width - (show_scrollbar_v ? scrollbar_width : 0.0f);
        float max_scroll_x = fmaxf(0.0f, content_width - viewport_width);

        bool animating = false;
        if (scroll_momentum_v.update(dt, accumulated_time, scroll_y, max_scroll_y)) {
            animating = true;
        }
        if (scroll_momentum_h.update(dt, accumulated_time, scroll_x, max_scroll_x)) {
            animating = true;
        }

        if (animating) {
            layout();
            set_dirty();
        }
    }

    void measure(const LayoutConstraints& constraints) override {
        // Viewport width (account for scrollbar)
        float viewport_width = constraints.max_width - (show_scrollbar_v ? scrollbar_width : 0.0f);

        // Create constraints for children - unlimited height since we scroll
        LayoutConstraints child_constraints;
        child_constraints.min_width = 0.0f;
        child_constraints.max_width = viewport_width;
        child_constraints.min_height = 0.0f;
        child_constraints.max_height = 100000.0f;  // Effectively unlimited

        // Measure children first, then compute content size
        content_width = 0.0f;
        content_height = 0.0f;

        for (Widget* child = first_child; child; child = child->next_sibling) {
            if (!(child->flags & WidgetFlags::Visible)) continue;

            // Measure child with constraints
            child->measure(child_constraints);

            // Each child contributes to content size
            content_width = fmaxf(content_width, child->preferred_width);
            content_height += child->preferred_height;
        }

        // Container uses its preferred_height if set, otherwise takes available space
        // This allows scroll containers to have a fixed size within a FlexContainer
        if (preferred_height <= 0.0f) {
            preferred_height = constraints.max_height;
        }
        if (preferred_width <= 0.0f) {
            preferred_width = constraints.max_width;
        }

        // Update rect size from preferred (respecting any fixed size we have)
        rect.width = fminf(preferred_width, constraints.max_width);
        rect.height = fminf(preferred_height, constraints.max_height);
    }

    void layout() override {
        // Viewport size (minus scrollbar if visible)
        float viewport_width = rect.width - (show_scrollbar_v ? scrollbar_width : 0.0f);
        float viewport_height = rect.height - (show_scrollbar_h ? scrollbar_width : 0.0f);

        // Layout children in a vertical stack (like FlexContainer Column)
        float y = rect.y - scroll_y;

        for (Widget* child = first_child; child; child = child->next_sibling) {
            if (!(child->flags & WidgetFlags::Visible)) continue;

            child->rect.x = rect.x - scroll_x;  // Apply horizontal scroll offset
            child->rect.y = y;
            // Use content_width if wider than viewport (for horizontal scrolling)
            child->rect.width = fmaxf(viewport_width, content_width);
            // ScrollContainer children always use their preferred size
            // (height_mode is for layout distribution in FlexContainer, not scroll containers)
            child->rect.height = child->preferred_height;

            child->layout();
            y += child->rect.height;
        }

        // Clamp vertical scroll position
        float max_scroll_y = fmaxf(0.0f, content_height - viewport_height);
        if (scroll_y > max_scroll_y) scroll_y = max_scroll_y;
        if (scroll_y < 0) scroll_y = 0;

        // Clamp horizontal scroll position
        float max_scroll_x = fmaxf(0.0f, content_width - viewport_width);
        if (scroll_x > max_scroll_x) scroll_x = max_scroll_x;
        if (scroll_x < 0) scroll_x = 0;

        // Update scrollbar geometry
        update_scrollbar_geometry();
        update_scrollbar_geometry_h();
    }

    void update_scrollbar_geometry() {
        if (!show_scrollbar_v) return;

        float viewport_height = rect.height - (show_scrollbar_h ? scrollbar_width : 0.0f);

        // Track area (between up/down buttons)
        track_top = rect.y + scrollbar_button_size;
        track_bottom = rect.y + rect.height - scrollbar_button_size;
        float track_height = track_bottom - track_top;

        // Thumb size proportional to visible content
        float visible_ratio = viewport_height / fmaxf(content_height, 1.0f);
        float thumb_height = fmaxf(track_height * fminf(visible_ratio, 1.0f), scrollbar_min_thumb);

        // Thumb position based on scroll
        float max_scroll = fmaxf(0.0f, content_height - viewport_height);
        float scroll_ratio = max_scroll > 0 ? scroll_y / max_scroll : 0.0f;
        float available_track = track_height - thumb_height;

        thumb_top = track_top + scroll_ratio * available_track;
        thumb_bottom = thumb_top + thumb_height;
    }

    void update_scrollbar_geometry_h() {
        if (!show_scrollbar_h) return;

        float viewport_width = rect.width - (show_scrollbar_v ? scrollbar_width : 0.0f);

        // Track area (between left/right buttons)
        track_left_h = rect.x + scrollbar_button_size;
        track_right_h = rect.x + rect.width - scrollbar_button_size
                        - (show_scrollbar_v ? scrollbar_width : 0.0f);
        float track_width = track_right_h - track_left_h;

        // Thumb size proportional to visible content
        float visible_ratio = viewport_width / fmaxf(content_width, 1.0f);
        float thumb_width = fmaxf(track_width * fminf(visible_ratio, 1.0f), scrollbar_min_thumb);

        // Thumb position based on scroll
        float max_scroll_x = fmaxf(0.0f, content_width - viewport_width);
        float scroll_ratio_h = max_scroll_x > 0 ? scroll_x / max_scroll_x : 0.0f;
        float available_track_h = track_width - thumb_width;

        thumb_left_h = track_left_h + scroll_ratio_h * available_track_h;
        thumb_right_h = thumb_left_h + thumb_width;
    }

    void render(RenderContext& ctx) override {
        // Calculate viewport
        float viewport_width = rect.width - (show_scrollbar_v ? scrollbar_width : 0.0f);
        float viewport_height = rect.height - (show_scrollbar_h ? scrollbar_width : 0.0f);
        float vp_top = rect.y;
        float vp_bottom = rect.y + viewport_height;

        // Propagate viewport bounds to virtualized widget descendants
        propagate_viewport_to_virtualized_widgets(first_child, vp_top, vp_bottom);

        // Clip to viewport
        D2D1_RECT_F clip_rect = D2D1::RectF(rect.x, rect.y, rect.x + viewport_width, rect.y + viewport_height);
        ctx.push_clip(clip_rect);

        // Render children (they position themselves with scroll offset)
        for (Widget* child = first_child; child; child = child->next_sibling) {
            if (!(child->flags & WidgetFlags::Visible)) continue;

            // Skip if completely outside viewport
            if (child->rect.y + child->rect.height < rect.y) continue;
            if (child->rect.y > rect.y + viewport_height) continue;

            child->render(ctx);
        }

        ctx.pop_clip();

        // Render vertical scrollbar
        if (show_scrollbar_v && content_height > viewport_height) {
            render_scrollbar(ctx);
        }

        // Render horizontal scrollbar
        if (show_scrollbar_h && content_width > viewport_width) {
            render_scrollbar_h(ctx);
        }
    }

    void render_scrollbar(RenderContext& ctx) {
        float sb_x = rect.x + rect.width - scrollbar_width;

        // Track background
        D2D1_RECT_F track_rect = D2D1::RectF(sb_x, rect.y, sb_x + scrollbar_width, rect.y + rect.height);
        ctx.fill_rect(track_rect, scrollbar_track_color);

        // Up button
        D2D1_RECT_F up_rect = D2D1::RectF(sb_x, rect.y, sb_x + scrollbar_width, rect.y + scrollbar_button_size);
        if (scrollbar_hover == ScrollbarHover::UpButton) {
            ctx.fill_rect(up_rect, Theme::BG_TERTIARY);
        }
        draw_arrow(ctx, sb_x + scrollbar_width / 2.0f, rect.y + scrollbar_button_size / 2.0f, true);

        // Down button
        D2D1_RECT_F down_rect = D2D1::RectF(sb_x, rect.y + rect.height - scrollbar_button_size,
                                            sb_x + scrollbar_width, rect.y + rect.height);
        if (scrollbar_hover == ScrollbarHover::DownButton) {
            ctx.fill_rect(down_rect, Theme::BG_TERTIARY);
        }
        draw_arrow(ctx, sb_x + scrollbar_width / 2.0f, rect.y + rect.height - scrollbar_button_size / 2.0f, false);

        // Thumb
        D2D1_RECT_F thumb_rect = D2D1::RectF(
            sb_x + scrollbar_thumb_margin,
            thumb_top,
            sb_x + scrollbar_width - scrollbar_thumb_margin,
            thumb_bottom
        );
        uint32_t thumb_color = (scrollbar_hover == ScrollbarHover::Thumb || scrollbar_dragging)
                               ? Theme::TEXT_MUTED : scrollbar_thumb_color;
        ctx.fill_rounded_rect(thumb_rect, 3.0f, thumb_color);
    }

    void draw_arrow(RenderContext& ctx, float cx, float cy, bool up) {
        ctx.brush->SetColor(color_from_argb(scrollbar_button_color));

        float size = 4.0f;
        if (up) {
            // Up arrow: point at top
            ctx.target->DrawLine(D2D1::Point2F(cx, cy - size), D2D1::Point2F(cx - size, cy + size / 2.0f), ctx.brush, 1.0f);
            ctx.target->DrawLine(D2D1::Point2F(cx, cy - size), D2D1::Point2F(cx + size, cy + size / 2.0f), ctx.brush, 1.0f);
        } else {
            // Down arrow: point at bottom
            ctx.target->DrawLine(D2D1::Point2F(cx, cy + size), D2D1::Point2F(cx - size, cy - size / 2.0f), ctx.brush, 1.0f);
            ctx.target->DrawLine(D2D1::Point2F(cx, cy + size), D2D1::Point2F(cx + size, cy - size / 2.0f), ctx.brush, 1.0f);
        }
    }

    void render_scrollbar_h(RenderContext& ctx) {
        float sb_y = rect.y + rect.height - scrollbar_width;
        float sb_width = rect.width - (show_scrollbar_v ? scrollbar_width : 0.0f);

        // Track background
        D2D1_RECT_F track_rect = D2D1::RectF(rect.x, sb_y, rect.x + sb_width, sb_y + scrollbar_width);
        ctx.fill_rect(track_rect, scrollbar_track_color);

        // Left button
        D2D1_RECT_F left_rect = D2D1::RectF(rect.x, sb_y,
                                            rect.x + scrollbar_button_size, sb_y + scrollbar_width);
        if (scrollbar_hover_h == ScrollbarHoverH::LeftButton) {
            ctx.fill_rect(left_rect, Theme::BG_TERTIARY);
        }
        draw_arrow_h(ctx, rect.x + scrollbar_button_size / 2.0f,
                     sb_y + scrollbar_width / 2.0f, true);  // true = left

        // Right button
        float right_btn_x = rect.x + sb_width - scrollbar_button_size;
        D2D1_RECT_F right_rect = D2D1::RectF(right_btn_x, sb_y,
                                              right_btn_x + scrollbar_button_size, sb_y + scrollbar_width);
        if (scrollbar_hover_h == ScrollbarHoverH::RightButton) {
            ctx.fill_rect(right_rect, Theme::BG_TERTIARY);
        }
        draw_arrow_h(ctx, right_btn_x + scrollbar_button_size / 2.0f,
                     sb_y + scrollbar_width / 2.0f, false);  // false = right

        // Thumb
        D2D1_RECT_F thumb_rect = D2D1::RectF(
            thumb_left_h,
            sb_y + scrollbar_thumb_margin,
            thumb_right_h,
            sb_y + scrollbar_width - scrollbar_thumb_margin
        );
        uint32_t thumb_color = (scrollbar_hover_h == ScrollbarHoverH::Thumb || scrollbar_dragging_h)
                               ? Theme::TEXT_MUTED : scrollbar_thumb_color;
        ctx.fill_rounded_rect(thumb_rect, 3.0f, thumb_color);
    }

    void draw_arrow_h(RenderContext& ctx, float cx, float cy, bool left) {
        ctx.brush->SetColor(color_from_argb(scrollbar_button_color));

        float size = 4.0f;
        if (left) {
            // Left arrow: point at left
            ctx.target->DrawLine(D2D1::Point2F(cx - size, cy), D2D1::Point2F(cx + size / 2.0f, cy - size), ctx.brush, 1.0f);
            ctx.target->DrawLine(D2D1::Point2F(cx - size, cy), D2D1::Point2F(cx + size / 2.0f, cy + size), ctx.brush, 1.0f);
        } else {
            // Right arrow: point at right
            ctx.target->DrawLine(D2D1::Point2F(cx + size, cy), D2D1::Point2F(cx - size / 2.0f, cy - size), ctx.brush, 1.0f);
            ctx.target->DrawLine(D2D1::Point2F(cx + size, cy), D2D1::Point2F(cx - size / 2.0f, cy + size), ctx.brush, 1.0f);
        }
    }

    bool on_mouse_wheel(float x, float y, float delta) override {
        (void)x; (void)y;  // Position not needed for scrolling

        // Calculate max scroll for bounds checking
        float viewport_height = rect.height - (show_scrollbar_h ? scrollbar_width : 0.0f);
        float max_scroll_y = fmaxf(0.0f, content_height - viewport_height);

        scroll_momentum_v.on_scroll_input(delta * scroll_speed, scroll_y, max_scroll_y);

        layout();
        set_dirty();

        return true;
    }

    bool on_mouse_down(float x, float y, int button) override {
        // x,y are relative to ScrollContainer - convert to absolute for comparisons
        float abs_x = rect.x + x;
        float abs_y = rect.y + y;

        // Check if click is in vertical scrollbar area first
        if (show_scrollbar_v) {
            float sb_x = rect.x + rect.width - scrollbar_width;

            if (abs_x >= sb_x) {
                // Up button
                if (abs_y < rect.y + scrollbar_button_size) {
                    scroll_by_line(-1);
                    return true;
                }

                // Down button
                if (abs_y > rect.y + rect.height - scrollbar_button_size) {
                    scroll_by_line(1);
                    return true;
                }

                // Thumb drag
                if (abs_y >= thumb_top && abs_y < thumb_bottom) {
                    scrollbar_dragging = true;
                    drag_start_y = abs_y;
                    drag_start_offset = scroll_y;
                    return true;
                }

                // Track click - page up/down
                if (abs_y < thumb_top) {
                    scroll_by_page(-1);
                } else {
                    scroll_by_page(1);
                }

                return true;
            }
        }

        // Check if click is in horizontal scrollbar area
        if (show_scrollbar_h) {
            float sb_y = rect.y + rect.height - scrollbar_width;
            float sb_width = rect.width - (show_scrollbar_v ? scrollbar_width : 0.0f);

            if (abs_y >= sb_y && abs_x < rect.x + sb_width) {
                // Left button
                if (abs_x < rect.x + scrollbar_button_size) {
                    scroll_by_column(-1);
                    return true;
                }

                // Right button
                if (abs_x > rect.x + sb_width - scrollbar_button_size) {
                    scroll_by_column(1);
                    return true;
                }

                // Thumb drag
                if (abs_x >= thumb_left_h && abs_x < thumb_right_h) {
                    scrollbar_dragging_h = true;
                    drag_start_x = abs_x;
                    drag_start_offset_x = scroll_x;
                    return true;
                }

                // Track click - page left/right
                if (abs_x < thumb_left_h) {
                    scroll_by_page_h(-1);
                } else {
                    scroll_by_page_h(1);
                }

                return true;
            }
        }

        // Forward to children (they have absolute positions from layout)
        for (Widget* child = first_child; child; child = child->next_sibling) {
            if (!(child->flags & WidgetFlags::Visible)) continue;
            if (child->hit_test(abs_x, abs_y)) {
                // Convert to child-relative coordinates
                float child_x = abs_x - child->rect.x;
                float child_y = abs_y - child->rect.y;
                if (child->on_mouse_down(child_x, child_y, button)) {
                    mouse_down_child = child;  // Track for mouse_up forwarding
                    return true;
                }
            }
        }

        return false;
    }

    bool on_mouse_up(float x, float y, int button) override {
        // Coordinate convention matches on_mouse_move: captured → absolute,
        // otherwise → relative. We're captured iff a drag is in progress.
        bool is_captured = mouse_down_child || scrollbar_dragging || scrollbar_dragging_h;
        float abs_x = is_captured ? x : (rect.x + x);
        float abs_y = is_captured ? y : (rect.y + y);

        // Handle scrollbar drag release first
        if (scrollbar_dragging) {
            scrollbar_dragging = false;
            mouse_down_child = nullptr;
            return true;
        }
        if (scrollbar_dragging_h) {
            scrollbar_dragging_h = false;
            mouse_down_child = nullptr;
            return true;
        }

        // Forward to child that received mouse_down
        if (mouse_down_child) {
            float child_x = abs_x - mouse_down_child->rect.x;
            float child_y = abs_y - mouse_down_child->rect.y;
            mouse_down_child->on_mouse_up(child_x, child_y, button);
            mouse_down_child = nullptr;
            return true;
        }

        return false;
    }

    bool on_mouse_move(float x, float y) override {
        // When captured (via EventDispatcher), x,y are ABSOLUTE. Otherwise they're RELATIVE.
        // We're captured if mouse_down_child is set OR scrollbar dragging.
        bool is_captured = mouse_down_child || scrollbar_dragging || scrollbar_dragging_h;

        // Handle vertical thumb drag (captured = absolute coords)
        if (scrollbar_dragging) {
            float delta_y = y - drag_start_y;
            float track_height = track_bottom - track_top;
            float thumb_height = thumb_bottom - thumb_top;
            float available_track = track_height - thumb_height;

            if (available_track > 0) {
                float viewport_height = rect.height - (show_scrollbar_h ? scrollbar_width : 0.0f);
                float max_scroll = fmaxf(0.0f, content_height - viewport_height);
                float scroll_delta = (delta_y / available_track) * max_scroll;

                scroll_y = fminf(fmaxf(drag_start_offset + scroll_delta, 0.0f), max_scroll);
                layout();
                set_dirty();
            }
            return true;
        }

        // Handle horizontal thumb drag (captured = absolute coords)
        if (scrollbar_dragging_h) {
            float delta_x = x - drag_start_x;
            float track_width = track_right_h - track_left_h;
            float thumb_width = thumb_right_h - thumb_left_h;
            float available_track = track_width - thumb_width;

            if (available_track > 0) {
                float viewport_width = rect.width - (show_scrollbar_v ? scrollbar_width : 0.0f);
                float max_scroll_x = fmaxf(0.0f, content_width - viewport_width);
                float scroll_delta = (delta_x / available_track) * max_scroll_x;

                scroll_x = fminf(fmaxf(drag_start_offset_x + scroll_delta, 0.0f), max_scroll_x);
                layout();
                set_dirty();
            }
            return true;
        }

        // Convert to absolute coordinates
        // When captured, coords are already absolute. Otherwise, convert from relative.
        float abs_x = is_captured ? x : rect.x + x;
        float abs_y = is_captured ? y : rect.y + y;

        // Update vertical hover state
        ScrollbarHover old_hover = scrollbar_hover;
        scrollbar_hover = ScrollbarHover::None;

        if (show_scrollbar_v) {
            float sb_x = rect.x + rect.width - scrollbar_width;

            if (abs_x >= sb_x) {
                if (abs_y < rect.y + scrollbar_button_size) {
                    scrollbar_hover = ScrollbarHover::UpButton;
                } else if (abs_y > rect.y + rect.height - scrollbar_button_size) {
                    scrollbar_hover = ScrollbarHover::DownButton;
                } else if (abs_y >= thumb_top && abs_y < thumb_bottom) {
                    scrollbar_hover = ScrollbarHover::Thumb;
                } else {
                    scrollbar_hover = ScrollbarHover::Track;
                }
            }
        }

        if (old_hover != scrollbar_hover) {
            set_dirty();
        }

        // Update horizontal hover state
        ScrollbarHoverH old_hover_h = scrollbar_hover_h;
        scrollbar_hover_h = ScrollbarHoverH::None;

        if (show_scrollbar_h) {
            float sb_y = rect.y + rect.height - scrollbar_width;
            float sb_width = rect.width - (show_scrollbar_v ? scrollbar_width : 0.0f);

            if (abs_y >= sb_y && abs_x < rect.x + sb_width) {
                if (abs_x < rect.x + scrollbar_button_size) {
                    scrollbar_hover_h = ScrollbarHoverH::LeftButton;
                } else if (abs_x > rect.x + sb_width - scrollbar_button_size) {
                    scrollbar_hover_h = ScrollbarHoverH::RightButton;
                } else if (abs_x >= thumb_left_h && abs_x < thumb_right_h) {
                    scrollbar_hover_h = ScrollbarHoverH::Thumb;
                } else {
                    scrollbar_hover_h = ScrollbarHoverH::Track;
                }
            }
        }

        if (old_hover_h != scrollbar_hover_h) {
            set_dirty();
        }

        // Forward hover events to children
        for (Widget* child = first_child; child; child = child->next_sibling) {
            if (!(child->flags & WidgetFlags::Visible)) continue;
            if (child->hit_test(abs_x, abs_y)) {
                // Convert to child-relative coordinates
                float child_x = abs_x - child->rect.x;
                float child_y = abs_y - child->rect.y;
                child->on_mouse_move(child_x, child_y);
            } else {
                // Clear hover if mouse left this child
                child->on_mouse_leave();
            }
        }

        return false;  // Don't consume - allow children to handle
    }

    bool on_mouse_leave() override {
        bool need_redraw = false;
        if (scrollbar_hover != ScrollbarHover::None) {
            scrollbar_hover = ScrollbarHover::None;
            need_redraw = true;
        }
        if (scrollbar_hover_h != ScrollbarHoverH::None) {
            scrollbar_hover_h = ScrollbarHoverH::None;
            need_redraw = true;
        }
        if (need_redraw) {
            set_dirty();
        }
        // Clear hover on all children
        for (Widget* child = first_child; child; child = child->next_sibling) {
            child->on_mouse_leave();
        }
        // Clear mouse_down tracking (mouse left the container)
        mouse_down_child = nullptr;
        return false;
    }

    bool on_double_click(float x, float y, int button) override {
        // Forward to children
        // x,y are relative to ScrollContainer - convert to absolute for hit testing
        float abs_x = rect.x + x;
        float abs_y = rect.y + y;
        for (Widget* child = first_child; child; child = child->next_sibling) {
            if (!(child->flags & WidgetFlags::Visible)) continue;
            if (child->hit_test(abs_x, abs_y)) {
                // Convert to child-relative coordinates
                float child_x = abs_x - child->rect.x;
                float child_y = abs_y - child->rect.y;
                if (child->on_double_click(child_x, child_y, button)) {
                    return true;
                }
            }
        }
        return false;
    }

    void scroll_by_line(int direction) {
        float viewport_height = rect.height - (show_scrollbar_h ? scrollbar_width : 0.0f);
        float max_scroll = fmaxf(0.0f, content_height - viewport_height);

        scroll_y += direction * 28.0f;  // ~1 row height
        scroll_y = fminf(fmaxf(scroll_y, 0.0f), max_scroll);

        layout();
        set_dirty();
    }

    void scroll_by_page(int direction) {
        float viewport_height = rect.height - (show_scrollbar_h ? scrollbar_width : 0.0f);
        float max_scroll = fmaxf(0.0f, content_height - viewport_height);

        scroll_y += direction * (viewport_height - 28.0f);  // Page minus one row
        scroll_y = fminf(fmaxf(scroll_y, 0.0f), max_scroll);

        layout();
        set_dirty();
    }

    void scroll_to(float y) {
        float viewport_height = rect.height - (show_scrollbar_h ? scrollbar_width : 0.0f);
        float max_scroll = fmaxf(0.0f, content_height - viewport_height);

        scroll_y = fminf(fmaxf(y, 0.0f), max_scroll);
        layout();
        set_dirty();
    }

    void ensure_visible(float item_top, float item_bottom) {
        float viewport_height = rect.height - (show_scrollbar_h ? scrollbar_width : 0.0f);

        if (item_top < scroll_y) {
            scroll_to(item_top);
        } else if (item_bottom > scroll_y + viewport_height) {
            scroll_to(item_bottom - viewport_height);
        }
    }

    // Horizontal scroll helpers
    void scroll_by_column(int direction) {
        float viewport_width = rect.width - (show_scrollbar_v ? scrollbar_width : 0.0f);
        float max_scroll_x = fmaxf(0.0f, content_width - viewport_width);

        scroll_x += direction * 40.0f;  // 40px per column
        scroll_x = fminf(fmaxf(scroll_x, 0.0f), max_scroll_x);

        layout();
        set_dirty();
    }

    void scroll_by_page_h(int direction) {
        float viewport_width = rect.width - (show_scrollbar_v ? scrollbar_width : 0.0f);
        float max_scroll_x = fmaxf(0.0f, content_width - viewport_width);

        scroll_x += direction * (viewport_width - 40.0f);  // Page minus one column
        scroll_x = fminf(fmaxf(scroll_x, 0.0f), max_scroll_x);

        layout();
        set_dirty();
    }

    void scroll_to_x(float x) {
        float viewport_width = rect.width - (show_scrollbar_v ? scrollbar_width : 0.0f);
        float max_scroll_x = fmaxf(0.0f, content_width - viewport_width);

        scroll_x = fminf(fmaxf(x, 0.0f), max_scroll_x);
        layout();
        set_dirty();
    }
};

// ============================================================================
// ProgressBar Widget - Horizontal progress bar (0-1 float)
// ============================================================================

struct ProgressBar : Widget {
    float progress = 0.0f;  // 0.0 to 1.0
    bool indeterminate = false;  // Pulse animation when total is unknown

    // Appearance
    uint32_t bg_color = StatusBar::PROGRESS_BG;    // Semi-transparent black
    uint32_t fill_color = StatusBar::PROGRESS_FILL;  // White
    float corner_radius = StatusBar::PROGRESS_BAR_CORNER;  // 2.0f

    // Indeterminate marquee runs continuously — keep the render loop alive.
    AnimGuard marquee_guard;

    ProgressBar() {
        preferred_width = StatusBar::PROGRESS_BAR_WIDTH;   // 200.0f
        preferred_height = StatusBar::PROGRESS_BAR_HEIGHT; // 4.0f
    }

    void measure(const LayoutConstraints& constraints) override {
        Widget::measure(constraints);
    }

    void render(RenderContext& ctx) override {
        D2D1_RECT_F bar_rect = D2D1::RectF(
            rect.x, rect.y,
            rect.x + rect.width, rect.y + rect.height
        );

        // Draw background track
        ctx.fill_rounded_rect(bar_rect, corner_radius, bg_color);

        if (indeterminate) {
            // Sliding highlight animation (marquee style)
            // Highlight bar is 30% of total width, slides left-to-right over 1.5 seconds
            constexpr float HIGHLIGHT_WIDTH_RATIO = 0.30f;
            constexpr int64_t CYCLE_MS = 1500;

            int64_t now = GetTickCount64();
            float t = static_cast<float>(now % CYCLE_MS) / static_cast<float>(CYCLE_MS);

            // t goes 0->1, position goes from -highlight_width to bar_width
            float highlight_width = rect.width * HIGHLIGHT_WIDTH_RATIO;
            float travel_distance = rect.width + highlight_width;
            float highlight_left = -highlight_width + t * travel_distance;
            float highlight_right = highlight_left + highlight_width;

            // Clip to bar bounds
            float clipped_left = fmaxf(0.0f, highlight_left);
            float clipped_right = fminf(rect.width, highlight_right);

            if (clipped_right > clipped_left) {
                D2D1_RECT_F fill_rect = D2D1::RectF(
                    rect.x + clipped_left, rect.y,
                    rect.x + clipped_right, rect.y + rect.height
                );
                ctx.fill_rounded_rect(fill_rect, corner_radius, fill_color);
            }
        } else {
            // Determinate progress bar
            if (progress > 0.0f) {
                float fill_width = rect.width * fminf(1.0f, progress);
                if (fill_width < rect.height) fill_width = rect.height;  // Minimum visible

                D2D1_RECT_F fill_rect = D2D1::RectF(
                    rect.x, rect.y,
                    rect.x + fill_width, rect.y + rect.height
                );
                ctx.fill_rounded_rect(fill_rect, corner_radius, fill_color);
            }
        }
    }

    void set_progress(float new_progress) {
        progress = fmaxf(0.0f, fminf(1.0f, new_progress));
        indeterminate = false;
        marquee_guard.stop();
        set_dirty();
    }

    void set_indeterminate(bool enable) {
        indeterminate = enable;
        if (enable) marquee_guard.start();
        else marquee_guard.stop();
        set_dirty();
    }
};

// ============================================================================
// FileChecklistItem Widget - Checkbox + filename for file selection lists
// ============================================================================

struct FileChecklistItem : Widget {
    bool checked = false;
    size_t file_index = 0;  // Index into stashable files list

    // File info (copied from SidebarFile for display)
    wchar_t filename[256] = {};
    wchar_t full_path[512] = {};
    uint32_t status_color = Theme::TEXT_PRIMARY;

    // Appearance (using StashDialog constants)
    float checkbox_size = StashDialog::FILE_CHECKBOX_SIZE;   // 14.0f
    float checkbox_spacing = StashDialog::FILE_CHECKBOX_SPACING;  // 8.0f

    uint32_t box_bg = StashDialog::INPUT_BG;
    uint32_t box_border = StashDialog::INPUT_BORDER;
    uint32_t box_border_hover = Theme::ACCENT;
    uint32_t check_color = StashDialog::CHECKBOX_CHECK;
    uint32_t text_color = Theme::TEXT_PRIMARY;
    uint32_t hover_bg = StashDialog::FILE_ITEM_HOVER;

    // Callback
    void (*on_change)(FileChecklistItem* item, bool checked, void* user_data) = nullptr;
    void* user_data = nullptr;

    FileChecklistItem() {
        flags |= WidgetFlags::Focusable;
        preferred_height = StashDialog::FILE_ITEM_HEIGHT;  // 24.0f
    }

    void measure(const LayoutConstraints& constraints) override {
        // Fixed height per item
        preferred_height = StashDialog::FILE_ITEM_HEIGHT;
        Widget::measure(constraints);
    }

    void render(RenderContext& ctx) override {
        // Draw hover background
        if (flags & WidgetFlags::Hovered) {
            D2D1_RECT_F bg_rect = D2D1::RectF(
                rect.x, rect.y,
                rect.x + rect.width, rect.y + rect.height
            );
            ctx.fill_rect(bg_rect, hover_bg);
        }

        // Checkbox position
        float cb_x = rect.x + 8.0f;
        float cb_y = rect.y + (rect.height - checkbox_size) / 2.0f;

        D2D1_RECT_F cb_rect = D2D1::RectF(cb_x, cb_y, cb_x + checkbox_size, cb_y + checkbox_size);

        // Draw checkbox background
        ctx.fill_rect(cb_rect, box_bg);

        // Draw checkbox border
        uint32_t border = (flags & (WidgetFlags::Hovered | WidgetFlags::Focused))
                          ? box_border_hover : box_border;
        ctx.brush->SetColor(color_from_argb(checked ? check_color : border));
        ctx.target->DrawRectangle(cb_rect, ctx.brush, 1.0f);

        // Draw checkmark if checked
        if (checked) {
            ctx.brush->SetColor(color_from_argb(check_color));

            float cx = cb_x + checkbox_size / 2.0f;
            float cy = cb_y + checkbox_size / 2.0f;
            float scale = checkbox_size / 16.0f;

            D2D1_POINT_2F p1 = D2D1::Point2F(cx - 3.0f * scale, cy);
            D2D1_POINT_2F p2 = D2D1::Point2F(cx - 0.5f * scale, cy + 2.5f * scale);
            D2D1_POINT_2F p3 = D2D1::Point2F(cx + 3.0f * scale, cy - 2.5f * scale);

            ctx.target->DrawLine(p1, p2, ctx.brush, 1.5f);
            ctx.target->DrawLine(p2, p3, ctx.brush, 1.5f);
        }

        // Draw filename
        if (filename[0]) {
            IDWriteTextFormat* fmt = g_text_format_body;
            if (fmt) {
                float text_x = cb_x + checkbox_size + checkbox_spacing;
                D2D1_RECT_F text_rect = D2D1::RectF(
                    text_x,
                    rect.y,
                    rect.x + rect.width - 8.0f,
                    rect.y + rect.height
                );

                // Use status color for filename
                ctx.draw_text(filename, wcslen(filename), fmt, text_rect, status_color);
            }
        }
    }

    bool on_key_down(int vk, bool ctrl, bool shift, bool alt) override {
        (void)ctrl; (void)shift; (void)alt;

        // Toggle with Space key when focused
        if (vk == VK_SPACE) {
            checked = !checked;
            if (on_change) {
                on_change(this, checked, user_data);
            }
            return true;
        }
        return false;
    }

    bool on_mouse_down(float x, float y, int button) override {
        (void)x; (void)y; (void)button;

        // Toggle checked state
        checked = !checked;

        // Fire callback
        if (on_change) {
            on_change(this, checked, user_data);
        }

        return true;
    }
};
